#include<bits/stdc++.h>
#define ll long long
using namespace std;
double a,b,n,ansa,ansb,mi=142857;
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%lf%lf%lf",&a,&b,&n);
	for(double i=1;i<=n;++i)
		for(double j=1;j<=n;++j)
			if(i/j>=a/b&&i/j-a/b<mi)mi=i/j-a/b,ansa=i,ansb=j;
	printf("%d %d",(int)ansa,(int)ansb);
	return false;
}
